from __future__ import annotations
from dataclasses import dataclass, field
from typing import Any, Callable


# ---------- Data types ----------

@dataclass
class Belief:
    """A fact the agent believes about the world."""
    predicate: str       # e.g. "location"
    args: tuple          # e.g. ("robot", "room_A")
    confidence: float = 1.0

    def __hash__(self): return hash((self.predicate, self.args))
    def __eq__(self, other): return (self.predicate, self.args) == (other.predicate, other.args)


@dataclass
class Desire:
    """A goal state the agent wants to achieve."""
    goal: str            # human-readable label
    condition: Callable[[set[Belief]], bool]
    priority: int = 5    # 1=lowest, 10=highest


@dataclass
class Plan:
    """A pre-compiled sequence of actions to achieve a goal."""
    name: str
    trigger: Callable[[set[Belief]], bool]   # when applicable
    steps: list[str]                         # action names in order


@dataclass
class Intention:
    """A desire the agent has committed to pursue."""
    desire: Desire
    plan: Plan
    step_index: int = 0  # which step we are currently on

    @property
    def current_action(self) -> str | None:
        if self.step_index < len(self.plan.steps):
            return self.plan.steps[self.step_index]
        return None

    def advance(self) -> None:
        self.step_index += 1

    @property
    def completed(self) -> bool:
        return self.step_index >= len(self.plan.steps)

class BDIAgent:
    def __init__(self, plan_library: list[Plan]):
        self.beliefs: set[Belief] = set()
        self.desires: list[Desire] = []
        self.intentions: list[Intention] = []
        self.plan_library = plan_library

    # ---- Belief Revision ----
    def perceive(self, percept: Belief) -> None:
        """Update beliefs from environment percept."""
        # Remove contradicting beliefs (same predicate+args, different confidence)
        self.beliefs.discard(percept)
        if percept.confidence > 0:
            self.beliefs.add(percept)

    # ---- Deliberation ----
    def deliberate(self) -> list[Desire]:
        """Pick which desires to pursue given current beliefs.
        Returns desires sorted by priority (highest first).
        """
        active = [
            d for d in self.desires
            if not d.condition(self.beliefs)  # not yet satisfied
        ]
        return sorted(active, key=lambda d: d.priority, reverse=True)

    # ---- Means-End Reasoning ----
    def select_plan(self, desire: Desire) -> Plan | None:
        """Find an applicable plan for the given desire."""
        for plan in self.plan_library:
            if plan.trigger(self.beliefs):
                return plan
        return None

    def adopt_intention(self, desire: Desire) -> bool:
        """Commit to a desire by adopting a plan."""
        # Do not re-adopt an already-active intention
        if any(i.desire is desire for i in self.intentions):
            return False
        plan = self.select_plan(desire)
        if plan is None:
            return False
        self.intentions.append(Intention(desire, plan))
        return True

    # ---- Execution ----
    def execute_step(self, env: dict) -> str | None:
        """Execute the next step of the highest-priority intention."""
        # Remove completed intentions
        self.intentions = [i for i in self.intentions if not i.completed]
        if not self.intentions:
            return None
        intention = self.intentions[0]  # highest priority is first
        action = intention.current_action
        intention.advance()
        return action

    # ---- BDI Loop ----
    def step(self, percepts: list[Belief], env: dict) -> str | None:
        """One full BDI reasoning cycle."""
        # 1. Update beliefs
        for p in percepts:
            self.perceive(p)
        # 2. Deliberate: choose which desires to activate
        top_desires = self.deliberate()[:2]  # limit to 2 simultaneous
        for desire in top_desires:
            self.adopt_intention(desire)
        # 3. Execute next action
        return self.execute_step(env)

from enum import Enum


class CommitmentStrategy(Enum):
    BLIND    = "blind"    # pursue until achieved, regardless of world changes
    SINGLE_MINDED = "single"  # abandon if belief that enabled it is now false
    OPEN_MINDED   = "open"    # abandon if goal no longer achievable


class CommittedBDIAgent(BDIAgent):
    """BDI agent with configurable commitment strategy."""

    def __init__(self, plan_library, strategy: CommitmentStrategy = CommitmentStrategy.OPEN_MINDED):
        super().__init__(plan_library)
        self.strategy = strategy

    def recheck_intentions(self) -> None:
        """Reconsider active intentions based on strategy."""
        if self.strategy == CommitmentStrategy.BLIND:
            return  # never reconsider

        surviving = []
        for intention in self.intentions:
            d = intention.desire
            if d.condition(self.beliefs):
                continue  # goal already achieved — drop

            if self.strategy == CommitmentStrategy.SINGLE_MINDED:
                # Drop if triggering plan is no longer applicable
                if not intention.plan.trigger(self.beliefs):
                    print(f"Dropping intention (single-minded): {d.goal}")
                    continue

            surviving.append(intention)
        self.intentions = surviving

    def step(self, percepts, env) -> str | None:
        for p in percepts:
            self.perceive(p)
        self.recheck_intentions()  # reconsider before acting
        top_desires = self.deliberate()[:2]
        for desire in top_desires:
            self.adopt_intention(desire)
        return self.execute_step(env)
